module counter8(
  input logic clk,
  input logic rst_n,
  output logic [7:0] count_q
);
  always_ff @(posedge clk or negedge rst_n) begin
    if (!rst_n) count_q <= '0;
    else count_q <= count_q + 8'd1;
  end
endmodule

module helper_decoder(
  input logic [1:0] sel,
  output logic [3:0] decoded
);
  assign decoded = 4'b0001 << sel;
endmodule

module ram_wrapper(
  input logic clk,
  input logic [7:0] write_data,
  output logic [7:0] read_data
);
  logic [7:0] mem [0:3];
  always_ff @(posedge clk) begin
    mem[0] <= write_data;
    read_data <= mem[0];
  end
endmodule
